import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, fireEvent } from '@testing-library/react'
import { ethers } from 'ethers'

/**
 * Cross-panel round trip (spec 058 T016, SC-003 logic-level guarantee): a QR
 * generated by RequestPanel, scanned by PayPanel, lands one confirmation away
 * from paying — right recipient, amount, currency, and note.
 */

const REQUESTER = ethers.getAddress('0x5555555555555555555555555555555555555555')
const USDC = '0x3c499c542cEF5E3811e1192ce70d8cC03d5c3359'
const TOKENS = {
  chainId: 137, networkName: 'Polygon',
  native: 'POL', nativeName: 'Polygon', nativeDecimals: 18,
  stable: 'USDC', stableName: 'USD Coin', stableAddress: USDC, stableDecimals: 6,
}

vi.mock('../hooks', () => ({
  useWallet: () => ({ isConnected: true, address: REQUESTER, chainId: 137 }),
  useWalletConnection: () => ({ connectWallet: vi.fn() }),
}))
vi.mock('../hooks/useChainTokens', () => ({ useChainTokens: () => TOKENS }))
vi.mock('../hooks/useClipboard', () => ({ useClipboard: () => ({ copied: false, copy: vi.fn() }) }))
vi.mock('qrcode.react', () => ({
  QRCodeSVG: (props) => <svg data-testid="request-qr" data-value={props.value} />,
}))
vi.mock('../hooks/useTransfer', () => ({
  useTransfer: () => ({
    status: 'idle', error: null,
    send: vi.fn(async () => ({ txHash: '0x1', route: 'gasless', id: '1' })),
    quoteGasless: () => true,
    balanceOf: () => '1000',
    refreshBalances: vi.fn(),
    tokens: TOKENS,
  }),
  TRANSFER_KIND: { NATIVE: 'native', STABLE: 'stable' },
}))
vi.mock('../hooks/useAddressScreening', () => ({
  useAddressScreening: () => ({ screenOne: vi.fn(async () => 'clear') }),
}))
vi.mock('../hooks/useUI', () => ({ useNotification: () => ({ showNotification: vi.fn() }) }))
vi.mock('wagmi', () => ({ useSwitchChain: () => ({ switchChainAsync: vi.fn(), isPending: false }) }))
vi.mock('../components/ui/AddressInput', () => ({
  default: ({ id, value, onChange, onResolvedChange }) => (
    <input
      id={id}
      aria-label="To"
      value={value}
      onChange={(e) => {
        onChange(e)
        onResolvedChange(/^0x[0-9a-fA-F]{40}$/.test(e.target.value) ? e.target.value : '')
      }}
    />
  ),
}))
vi.mock('../components/ui/AddressBookButton', () => ({ default: () => null }))
const scanHolder = { payload: '' }
vi.mock('../components/ui/QRScanner', () => ({
  default: ({ isOpen, onScanSuccess }) => isOpen ? (
    <button type="button" onClick={() => onScanSuccess(scanHolder.payload)}>simulate scan</button>
  ) : null,
}))

import RequestPanel from '../components/fairwins/RequestPanel'
import PayPanel from '../components/fairwins/PayPanel'

const typeAmount = (digits) => {
  for (const d of digits) {
    fireEvent.click(screen.getByRole('button', { name: d === '.' ? 'Decimal point' : d }))
  }
}

describe('Request → scan → Pay round trip (spec 058 US2/SC-003)', () => {
  beforeEach(() => { localStorage.clear() })

  it('a generated request prefills the payer one confirmation away from paying', async () => {
    // 1. The requester generates a 12.5 USDC request with a note.
    const request = render(<RequestPanel />)
    typeAmount(['1', '2', '.', '5'])
    fireEvent.change(screen.getByLabelText(/what's it for/i), { target: { value: 'pizza night' } })
    fireEvent.click(screen.getByRole('button', { name: /^request$/i }))
    const uri = screen.getByTestId('request-qr').getAttribute('data-value')
    expect(uri).toMatch(/^ethereum:/)
    request.unmount()

    // 2. The payer scans that exact code in the Pay view.
    scanHolder.payload = uri
    render(<PayPanel />)
    fireEvent.click(screen.getByRole('button', { name: /scan qr code/i }))
    fireEvent.click(screen.getByRole('button', { name: /simulate scan/i }))

    // 3. Everything is prefilled, ready to confirm.
    expect(screen.getByLabelText('To')).toHaveValue(REQUESTER)
    expect(screen.getByTestId('amount-keypad-hero')).toHaveTextContent('12.5')
    expect(screen.getByLabelText('Currency')).toHaveValue('stable')
    expect(screen.getByLabelText('Note')).toHaveValue('pizza night')
    const pay = screen.getByRole('button', { name: /^pay$/i })
    await vi.waitFor(() => expect(pay).toBeEnabled())
  })
})
